import json
with open('results/analysis.json') as f:
    a = json.load(f)

# Show detailed score diffs
print('=== Score Differences by Dimension ===')
import numpy as np
conditions = ['refine_x1', 'refine_x2', 'refine_x3', 'best_of_4', 'best_of_4_refine']
dims = ['Coherence', 'Creativity', 'Engagement', 'Character', 'Prose Quality', 'Emotional Impact']

# Load full results for more detail
with open('results/full_results.json') as f:
    r = json.load(f)

for cond in conditions:
    diffs = {d: [] for d in dims}
    for ev in r['evaluations']:
        if cond in ev:
            bs = ev[cond].get('baseline_scores', {})
            cs = ev[cond].get('condition_scores', {})
            for d in dims:
                if d in bs and d in cs:
                    diffs[d].append(cs[d] - bs[d])
    print(f'\n{cond}:')
    for d in dims:
        vals = diffs[d]
        if vals:
            print(f'  {d}: mean={np.mean(vals):+.2f}, n={len(vals)}')

# Text metrics comparison
print('\n=== Text Metrics ===')
for key in ['word_count', 'vocab_richness', 'distinct_2']:
    print(f'\n{key}:')
    for cond in ['baseline'] + conditions:
        m = a['text_metrics'].get(cond, {}).get(key, {})
        if m:
            print(f'  {cond}: {m[\"mean\"]:.2f} ± {m[\"std\"]:.2f}')
